import{_ as e,a as t,b as a,c as r}from"./chunks/Optical.DpFvXLpK.js";import{_ as o,c as s,a0 as n,o as l}from"./chunks/framework.BOr1CWtK.js";const p="/assets/SwiftPro/GPS.png",d="/assets/SwiftProMax/SwiftProMaxFrontSide.png",c="/assets/SwiftProMax/SwiftProMaxBackSide.png",P=JSON.parse('{"title":"Swift Pro-Max Drone","description":"","frontmatter":{},"headers":[],"relativePath":"docs/swiftProMax/description.md","filePath":"docs/swiftProMax/description.md"}'),g={name:"docs/swiftProMax/description.md"};function m(h,i,f,u,y,S){return l(),s("div",null,i[0]||(i[0]=[n('<h1 id="swift-pro-max-drone" tabindex="-1">Swift Pro-Max Drone <a class="header-anchor" href="#swift-pro-max-drone" aria-label="Permalink to &quot;Swift Pro-Max Drone&quot;">​</a></h1><h2 id="description" tabindex="-1">Description <a class="header-anchor" href="#description" aria-label="Permalink to &quot;Description&quot;">​</a></h2><p>The Swift Pro-Max Drone is an enhanced version of the Pro model, offering greater endurance and more advanced features for demanding applications.</p><h2 id="payload-capacity" tabindex="-1">Payload Capacity <a class="header-anchor" href="#payload-capacity" aria-label="Permalink to &quot;Payload Capacity&quot;">​</a></h2><ul><li><strong>Maximum Payload</strong>: [Specify Payload Capacity]</li></ul><h2 id="images" tabindex="-1">Images <a class="header-anchor" href="#images" aria-label="Permalink to &quot;Images&quot;">​</a></h2><p>Swift Pro Drone Schematic Front Side image</p><h2 id="flight-time" tabindex="-1">Flight Time <a class="header-anchor" href="#flight-time" aria-label="Permalink to &quot;Flight Time&quot;">​</a></h2><ul><li><strong>Maximum Flight Time</strong>: [Specify Flight Time]</li></ul><h2 id="application" tabindex="-1">Application <a class="header-anchor" href="#application" aria-label="Permalink to &quot;Application&quot;">​</a></h2><p>Suitable for high-end aerial photography, industrial inspections, and large-scale surveys.</p><h2 id="components-used" tabindex="-1">Components Used <a class="header-anchor" href="#components-used" aria-label="Permalink to &quot;Components Used&quot;">​</a></h2><ul><li><p><strong>Flight Controller</strong>: <a href="https://flywoo.net/products/goku-gn745-45a-aio-bl_32-mpu6000-v3?srsltid=AfmBOorbbwncbJfNjdSvtDfeR1pO7N6U7WJpLcxdW_EToCIce4uHlw5y" target="_blank">FIYWOO GOKU GN7 45 AIO V3</a></p><div style="display:flex;align-items:center;"><div style="flex:1;"><p> The FIYWOO GOKU GN7 45 AIO V3 is a highly integrated flight controller designed for advanced drone applications. It features a 4-in-1 design, combining a flight controller, ESC (Electronic Speed Controller), and other essential components into a single compact unit. This integration simplifies the build process, reduces wiring complexity, and minimizes weight, making it ideal for high-performance and racing drones. </p></div><div style="flex:1;text-align:right;"><img src="'+e+'" alt="FIYWOO GOKU GN7 45 AIO V3" width="400" style="margin-right:0px;"></div></div><p><strong>Key Features:</strong></p><ul><li><strong>Processor:</strong> Equipped with a high-performance flight controller processor for smooth and reliable operation.</li><li><strong>ESC Integration:</strong> Includes a 45A ESC, providing efficient power management and support for high-current motors.</li><li><strong>Compatibility:</strong> Supports various flight stacks and is compatible with popular drone flight software like Betaflight, iNav, and others.</li><li><strong>Sensors:</strong> Integrates essential sensors for accurate flight control and stabilization.</li><li><strong>Build Quality:</strong> Designed with durability and reliability in mind, suitable for both professional and hobbyist applications.</li></ul></li><li><p><strong>Microprocessor</strong>: <a href="https://www.raspberrypi.com/products/raspberry-pi-zero-2-w/" target="_blank">Raspberry Pi Zero 2W</a></p><div style="display:flex;align-items:center;"><div style="flex:1;"><p> The Raspberry Pi Zero 2W features a 1GHz quad-core Arm Cortex-A53 CPU, 512MB SDRAM, and built-in 2.4GHz wireless LAN and Bluetooth 4.2 with BLE. It includes a mini HDMI port, micro USB OTG port, microSD card slot, CSI-2 camera connector, and a HAT-compatible 40-pin header. It supports 1080p30 video decoding and encoding, OpenGL ES 1.1 and 2.0 graphics, and is powered via micro USB. Measuring 65mm x 30mm, it is compact and versatile for various projects. </p></div><div style="flex:1;text-align:right;"><img src="'+t+'" alt="Raspberry Pi Zero 2W" width="1500" style="margin-right:0px;"></div></div></li><li><p><strong>Lidar</strong>: <a href="https://holybro.com/products/st-vl53l1x-lidar/" target="_blank">VL53L1X</a></p></li><li><p>The VL53L1X is a high-speed Time-of-Flight laser-ranging sensor from the ST FlightSense™ series.</p><div style="display:flex;align-items:center;"><div style="flex:1;"><p><strong>Operating Voltage</strong> &gt;2.8 V </p><p><strong>Communication Type</strong> I²C </p><p><strong>Max Range</strong> 120 CM </p><p><strong>Min Range</strong> 5 CM </p></div><div style="flex:1;text-align:right;"><img src="'+a+'" alt="Raspberry Pi Zero 2W" width="200" style="margin-right:0px;"></div></div></li><li><p><strong>Optical Flow Sensor</strong>: <a href="https://holybro.com/products/pmw3901-optical-flow-sensor" target="_blank">Holybro PMW3901 Optical Flow Sensor</a></p><div style="display:flex;align-items:center;"><div style="flex:1;"><p> The Holybro PMW3901 Optical Flow Sensor is a compact, UART-based sensor with a built-in BEC and pre-soldered 6-pin JST GH connector. It&#39;s compatible with PX4 and Ardupilot flight controllers and uses the same data format as the discontinued CX-OF model. Specs: 14 x 11 x 5 mm, 0.6 g, 19200 baud rate, 95 Hz frame rate, 2.0-3.6V power, 10 mA current. Data Format: Includes X/Y motion bytes, checksum, and surface quality. Package: Sensor, 170mm GH6P cable, TPU case. </p></div><div style="flex:1;text-align:right;"><img src="'+r+'" alt="Raspberry Pi Zero 2W" width="200" style="margin-right:0px;"></div></div></li><li><p><strong>GPS Sensor</strong>: <a href="https://geprc.com/product/gep-m10-series-gps-module/" target="_blank">GEPRC GEP-M10 GPS Series</a></p><div style="display:flex;align-items:center;"><div style="flex:1;"><p> The GEPRC GEP-M10 GPS series, featuring the u-blox M10050 chip, supports GPS, BDS, Galileo, QZSS, and SBAS for joint positioning with up to 32 satellites. It comes in 12x12mm and 18x18mm antenna sizes for improved reception. The module includes a built-in Flash chip and Farad capacitor for fast hot starts. Optional QMC5883L/IST8310 magnetometer and DPS310 barometer provide precise azimuth and altitude data. </p></div><div style="flex:1;text-align:right;"><img src="'+p+'" alt="Raspberry Pi Zero 2W" width="200" style="margin-right:0px;"></div></div><p><strong>Specs::</strong></p><ul><li><strong>Size:</strong> 15x15x7.5mm (nano), 22x22x8.2mm.</li><li><strong>Weight:</strong> 4.1g (nano), 7.8g</li><li><strong>Accuracy:</strong> Horizontal 1.5m, Speed 0.05 m/s</li></ul></li><li><p><strong>Motors</strong>: [Specify Model]</p></li><li><p><strong>Batteries</strong>: [Specify Model]</p></li></ul><h2 id="schematic" tabindex="-1">Schematic <a class="header-anchor" href="#schematic" aria-label="Permalink to &quot;Schematic&quot;">​</a></h2><p><img src="'+d+'" alt="Swift Pro Drone Schematic Front Side"></p><p><img src="'+c+'" alt="Swift Pro Drone Schematic Back Side"></p>',16)]))}const v=o(g,[["render",m]]);export{P as __pageData,v as default};
